// jetbrainsMonoFont.ts — JetBrains Mono(웹폰트, base64 내장) — 코드·터미널 글꼴 설정용.
// 터미널/에디터 WebView 주입 HTML 의 @font-face 로 사용(외부 네트워크 의존 없음).
// 출처: JetBrains Mono (OFL-1.1) https://github.com/JetBrains/JetBrainsMono
export const JBM_REGULAR_B64 = '';
export const JBM_BOLD_B64 = '';

/** 주입 HTML <style> 에 넣을 @font-face 블록. */
export function jetbrainsMonoFontFaceCss(): string {
  return `
@font-face { font-family: 'JetBrains Mono'; font-weight: 400; font-style: normal; src: url(data:font/woff2;base64,${JBM_REGULAR_B64}) format('woff2'); }
@font-face { font-family: 'JetBrains Mono'; font-weight: 700; font-style: normal; src: url(data:font/woff2;base64,${JBM_BOLD_B64}) format('woff2'); }
`;
}
